var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이런 날이 오리란 건 예상하고 있었습니다.","JPN":"こんな日が来るだろうと思っていました。","ENG":"I expected this day to come.","TWN":"我早就料到會有這麼一天。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"추산할 수 없는 감정을 추산하여 이름을 붙이는 게 법학이니까요.","JPN":"推し測ることのできない感情を推し測って名前を付けるのが法学なのですから。","ENG":"Law is about quantifying emotions that cannot be quantified.","TWN":"因為法學就是推算無法推算的感情再替它命名。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저는 당신의 변호인이고, 그렇기에 저는 당신을 이해하고 있습니다.","JPN":"私はあなたの弁護士ですので、あなたを理解しています。","ENG":"I am your attorney, and so I understand your position.","TWN":"我是你的律師，所以我懂你在想什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저는 의뢰인의 정당성을 입증하고, 약자를 보호하는 일에 평생을 바쳤습니다.","JPN":"私は依頼人の正当性を立証し、弱者を保護することに生涯を捧げました。","ENG":"I have spent my whole life in proving the validity of my clients and protecting the weak.","TWN":"我將我的一生都用來證明委託人的清白，以及保護弱小。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"강자들은 마음만 먹으면 쉽게 약자를 짓밟을 수 있으니까요.","JPN":"強者はその気になれば簡単に弱者を踏みにじることができますからね。","ENG":"As the strong are able to crush the weak effortlessly.","TWN":"因為強者可以輕易蹂躪弱者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"관리자님, 누명이 어떻게 사람의 마음을 무너뜨리는지 알고 계십니까?","JPN":"冤罪がどうやって人の心を崩壊させるかご存じでしょうか？","ENG":"Administrator, do you know how being falsely accused can demoralize someone?","TWN":"管理者，你知道冤屈是如何擊垮一個人的內心嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"형량에 대한 공포나, 피해자가 쏟아내는 원한 같은 건 부수적일 뿐입니다.","JPN":"量刑に対する恐怖や被害者が吐露する恨みなどは付随的なものに過ぎません。","ENG":"The fear of the sentence or the resentment from the victim is all collateral.","TWN":"對量刑的恐懼，或是來自受害者的怨恨都只是其次。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"자신의 편에 서 있는 사람이 세상에 없다고 느낄 때의 고독함은,","JPN":"自分の味方になってくれる人がこの世にひとりもいないと感じたときの孤独感は、","ENG":"The loneliness one experiences when they feel like no one is on their side,","TWN":"最可怕的是，彷彿這個世界上沒有人站在自己這一邊，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"버틸 수 있는 범주의 것이 아닙니다.","JPN":"耐えられる種類のものではありません。","ENG":"it's not something one can withstand.","TWN":"這樣的孤獨感不是一般人可以承受的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그러한 아픔을 겪는 사람이 세상에 없길 바랐기에,","JPN":"そのような苦しみを味わう人をこの世から無くすために、","ENG":"I didn't want anybody to go through that suffering.","TWN":"我希望世界上不要有人經歷這種痛苦，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저는 호수의 지식을 원했습니다.","JPN":"私は湖の知識を手に入れたいと思いました。","ENG":"So I yearned for the knowledge of the Lake.","TWN":"所以我想要湖水的知識。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회가 세상의 슬픔을 없애 주길 원했습니다.","JPN":"学会が世の中の悲しみをなくしてくれることを願ったのです。","ENG":"I yearned for the Society to erase all sorrow from the face of this earth.","TWN":"我希望學會能夠消除這個世界的痛苦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"관리자님. 저는 당신의 고독을 알고 있습니다.","JPN":"私はあなたの孤独を知っています。","ENG":"Administrator. I know of your loneliness.","TWN":"管理者，我明白你的孤獨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신이 얼마나 많은 선택의 순간들을 마주했었는지.","JPN":"あなたがどれほど多くの選択の瞬間に立ち会ってきたか。","ENG":"I know the countless number of times you were at a crossroads.","TWN":"我也知道你需要面對許多抉擇的時刻，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그 순간들마다, 얼마나 많은 고통에 시달렸는지도.","JPN":"その瞬間のたびに、どれだけ多くの苦痛を味わってきたか。","ENG":"And I know how much suffering you went through for each of those moments.","TWN":"在每個抉擇的瞬間，有多麼的痛苦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저는 그런 이에게 세상이 멸망한 책임을 물을 만큼 어리석지 않습니다.","JPN":"私はそんなあなたに世界が滅亡した責任を問うほど愚かではありません。","ENG":"I am not foolish enough to hold you responsible for the end of the world.","TWN":"我沒有愚蠢到對承受那些痛苦的人，追究世界滅亡的責任。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…관리자님.","JPN":"……管理者さん。","ENG":"...Administrator.","TWN":"……管理者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신이 잘못한 것은 아무것도 없습니다.","JPN":"あなたの過ちは何ひとつありません。","ENG":"You have done nothing wrong.","TWN":"你沒有做錯什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"세상에 혼자 남겨진 듯한 기분이 들 때면.","JPN":"この世にひとり取り残されたような気分になるときは。","ENG":"When you feel like you're alone in this world,","TWN":"當你覺得這個世界只有你一個人時，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신을 위한 변호인이 여기 있다는 것을.","JPN":"あなたの弁護士がここにいるということを。","ENG":"remember that your attorney is here.","TWN":"請絕對不要忘記，你的律師就在這裡，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신을 이해하고 있는 사람이 여기 있다는 걸, 결코 잊지 말도록 하십시오.","JPN":"あなたを理解している人がここにいるということを、決して忘れないでください。","ENG":"Remember that I am on your side.","TWN":"明白你的人就在這裡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};